library(shiny)
library(EBImage)
library(openxlsx)


# UI for the Shiny App
base64_image <- "data:image/png;base64,"

# UI for the Shiny App
options(shiny.maxRequestSize = 200*1024^2)
ui <- fluidPage(
  div(id = "header",
      tags$img(src = base64_image, alt = "Logo", height = "50px"),
      
  ),
  
  sidebarLayout(
    sidebarPanel(
      fileInput("images", "Upload Images (JPEG or TIFF)", 
                multiple = TRUE, accept = c(".jpg", ".jpeg", ".tif", ".tiff")),
      numericInput("pixel_to_micron", "Pixel-to-Micron Ratio (µm/pixel):", value = 1.0, min = 0.01),
      radioButtons("mode", "Threshold Selection Mode:", 
                   choices = c("Batch Mode" = "batch", "Individual Mode" = "individual"),
                   selected = "individual"),
      fluidRow(
        column(2, align = "center", actionButton("threshold_minus", "-")),
        column(8, sliderInput("threshold", "Threshold:", min = 0, max = 1, value = 0.5, step = 0.01)),
        column(2, align = "center", actionButton("threshold_plus", "+"))
      ),
      actionButton("analyze", "Analyse Images"),
      actionButton("next_image", "Next Image"),
      actionButton("prev_image", "Previous Image"),
      downloadButton("download", "Download Results")
    ),
    mainPanel(
      h4("Image and Analysis Preview"),
      plotOutput("image_plot", height = "500px"),
      textOutput("current_image_text"),
      h4("Results Table"),
      tableOutput("results")
    )
  )
)


# Server logic for the Shiny App
server <- function(input, output, session) {
  results <- reactiveVal(data.frame(
    Image = character(), 
    Threshold = numeric(), 
    Spheroid_Area_Pixels = numeric(), 
    Spheroid_Area_µm2 = numeric(),
    Eccentricity = numeric()
  ))
  
  images <- reactiveVal(NULL)
  thresholds <- reactiveVal(NULL)
  current_index <- reactiveVal(1)
  analyzed_images <- reactiveVal(NULL)
  analysis_done <- reactiveVal(FALSE)
  
  # Load images
  observeEvent(input$images, {
    req(input$images)
    img_list <- lapply(input$images$datapath, function(path) {
      tryCatch({
        img <- readImage(path)
        img <- if (length(dim(img)) == 3) channel(img, "gray") else img
        img
      }, error = function(e) {
        warning(paste("Failed to load image:", path, "-", e$message))
        NULL
      })
    })
    
    img_list <- Filter(Negate(is.null), img_list)
    
    if (length(img_list) > 0) {
      images(img_list)
      thresholds(rep(0.5, length(img_list))) 
      current_index(1)
      analyzed_images(NULL)
      analysis_done(FALSE)
    } else {
      showModal(modalDialog("No valid images uploaded."))
    }
  })
  output$download <- downloadHandler(
    filename = function() {
      paste0("spheroid_results_", format(Sys.time(), "%Y%m%d-%H%M%S"), ".xlsx")
    },
    content = function(file) {
      # only proceed if analysis has been run and we have rows
      req(analysis_done())
      df <- results()
      validate(need(nrow(df) > 0, "No results to download yet."))
      openxlsx::write.xlsx(df, file)
    }
  )
  # Navigation
  observeEvent(input$next_image, { 
    if (!is.null(images()) && current_index() < length(images())) {
      current_index(current_index() + 1)
    }
  })
  
  observeEvent(input$prev_image, { 
    if (!is.null(images()) && current_index() > 1) {
      current_index(current_index() - 1)
    }
  })
  
  observeEvent(current_index(), {
    idx <- current_index()
    isolate({
      if (!is.null(thresholds()) && idx <= length(thresholds())) {
        updateSliderInput(session, "threshold", value = thresholds()[[idx]])
      }
    })
  })
  
  observeEvent(input$threshold_minus, {
    new_value <- max(input$threshold - 0.01, 0)
    updateSliderInput(session, "threshold", value = new_value)
  })
  
  observeEvent(input$threshold_plus, {
    new_value <- min(input$threshold + 0.01, 1)
    updateSliderInput(session, "threshold", value = new_value)
  })
  
  observeEvent(input$threshold, {
    if (input$mode == "individual" && !is.null(thresholds())) {
      idx <- current_index()
      threshold_list <- thresholds()
      if (idx <= length(threshold_list)) {
        threshold_list[[idx]] <- input$threshold
        thresholds(threshold_list)
      }
    }
  })
  
  # Analyse images
  observeEvent(input$analyze, {
    req(images())
    px_to_um <- input$pixel_to_micron
    all_results <- data.frame(
      Image = character(), 
      Threshold = numeric(), 
      Spheroid_Area_Pixels = numeric(), 
      Spheroid_Area_µm2 = numeric(),
      Eccentricity = numeric()
    )
    
    analyzed_list <- list()
    
    for (i in seq_along(images())) {
      img <- images()[[i]]
      threshold <- if (input$mode == "batch") input$threshold else thresholds()[[i]]
      binary <- img < threshold   # if object is darker than background
      # binary <- img > threshold # if brighter than background
      binary <- opening(binary, makeBrush(5, shape = "disc"))
      binary <- fillHull(binary)  
      binary <- closing(binary, makeBrush(3, shape = "disc"))  
      
      # Identify connected components
      labeled <- bwlabel(binary)
      features_shape <- computeFeatures.shape(labeled)
      features_moment <- computeFeatures.moment(labeled)
      
      if (nrow(features_shape) > 0 && nrow(features_moment) > 0) {
        max_idx <- which.max(features_shape[, "s.area"])
        largest_binary <- labeled == max_idx
        largest_binary <- fillHull(largest_binary)
        
        # Compute area
        spheroid_area_pixels <- sum(largest_binary)
        Spheroid_Area_µm2 <- spheroid_area_pixels * (px_to_um ^ 2)
        
        # Use m.eccentricity for eccentricity
        if ("m.eccentricity" %in% colnames(features_moment)) {
          eccentricity <- features_moment[max_idx, "m.eccentricity"]
          if (eccentricity < 0.05) {
            eccentricity <- 0  # Round near-zero values
          }
        } else {
          eccentricity <- NA
        }
        
        analyzed_list[[i]] <- largest_binary
        all_results <- rbind(all_results, data.frame(
          Image = input$images$name[i],
          Threshold = threshold,
          Spheroid_Area_Pixels = spheroid_area_pixels,
          Spheroid_Area_µm2 = Spheroid_Area_µm2,
          Eccentricity = eccentricity
        ))
      } else {
        analyzed_list[[i]] <- matrix(0, nrow = dim(img)[1], ncol = dim(img)[2])  
      }
    }
    
    analyzed_images(analyzed_list)
    results(all_results[order(all_results$Image), ])
    analysis_done(TRUE)
  })
  
  # Output image with red outline before analysis and blue fill after analysis
  output$image_plot <- renderPlot({
    par(mar = c(0.1, 0.1, 0.1, 0.1))
    req(images())
    
    idx <- current_index()
    img <- images()[[idx]]
    
    threshold <- if (input$mode == "batch") input$threshold else thresholds()[[idx]]
    binary <- img > threshold
    binary <- opening(1 - binary, makeBrush(5, shape = "disc"))
    
    
    
    outline <- dilate(binary, makeBrush(3, shape = "disc")) & !binary
    outline <- as.Image(outline)
    
    blue_channel <- img
    red_channel <- if (!analysis_done()) img + outline else img  # Red outline before analysis
    green_channel <- img
    
    if (!is.null(analyzed_images()) && length(analyzed_images()) >= idx) {
      largest_binary <- analyzed_images()[[idx]]
      blue_channel <- largest_binary  # Blue fill after analysis
    }
    
    final_img <- rgbImage(
      red = pmin(red_channel, 1),
      green = pmin(green_channel, 1),
      blue = pmin(blue_channel, 1)
    )
    
    plot(as.raster(final_img), main = paste("Threshold =", round(threshold, 2)))
  })
  
  output$results <- renderTable({ results() })
}

shinyApp(ui = ui, server = server)


